DECLARE @org UNIQUEIDENTIFIER = (SELECT TOP 1 id FROM organizations WHERE slug='ai-media-group' ORDER BY created_at);
IF @org IS NULL SET @org = (SELECT TOP 1 id FROM organizations ORDER BY created_at);
IF @org IS NULL THROW 50032, 'No organization exists for tool registry seed.', 1;
DECLARE @adminRole UNIQUEIDENTIFIER = (SELECT TOP 1 id FROM roles WHERE organization_id=@org AND code='super_admin');

DECLARE @perms TABLE(code NVARCHAR(120), description NVARCHAR(255));
INSERT INTO @perms VALUES
('ai_tools.view','View AI tools'),('ai_tools.view_details','View AI tool details'),('ai_tools.view_calls','View AI tool calls'),('ai_tools.view_inputs','View tool inputs'),('ai_tools.view_outputs','View tool outputs'),('ai_tools.view_cost','View tool cost'),('ai_tools.view_security','View tool security'),('ai_tools.create','Create AI tools'),('ai_tools.edit','Edit AI tools'),('ai_tools.validate','Validate AI tools'),('ai_tools.test','Test AI tools'),('ai_tools.simulate','Simulate AI tools'),('ai_tools.publish','Publish AI tools'),('ai_tools.enable','Enable AI tools'),('ai_tools.disable','Disable AI tools'),('ai_tools.maintenance','Place tools in maintenance'),('ai_tools.duplicate','Duplicate AI tools'),('ai_tools.deprecate','Deprecate AI tools'),('ai_tools.archive','Archive AI tools'),('ai_tools.manage_credentials','Manage tool credentials'),('ai_tools.rotate_credentials','Rotate tool credentials'),('ai_tools.manage_schemas','Manage tool schemas'),('ai_tools.manage_permissions','Manage tool permissions'),('ai_tools.manage_agent_mappings','Manage agent mappings'),('ai_tools.manage_capability_mappings','Manage capability mappings'),('ai_tools.manage_workflow_mappings','Manage workflow mappings'),('ai_tools.manage_rate_limits','Manage tool rate limits'),('ai_tools.manage_quotas','Manage tool quotas'),('ai_tools.manage_costs','Manage tool costs'),('ai_tools.manage_retries','Manage retries'),('ai_tools.manage_fallbacks','Manage fallbacks'),('ai_tools.manage_circuit_breakers','Manage circuit breakers'),('ai_tools.retry_calls','Retry tool calls'),('ai_tools.recover_calls','Recover tool calls'),('ai_tools.apply_recommendations','Apply tool recommendations'),('ai_tools.generate_ai','Generate tools with AI'),('ai_tools.generate_documentation','Generate tool documentation'),('ai_tools.export','Export tool registry'),('ai_tools.manage_governance','Manage tool governance'),('ai_tools.emergency_override','Use tool emergency override');
MERGE permissions AS target USING (SELECT code,description FROM @perms) AS source ON target.code=source.code
WHEN MATCHED THEN UPDATE SET description=source.description, updated_at=SYSUTCDATETIME()
WHEN NOT MATCHED THEN INSERT (code,description) VALUES (source.code,source.description);
IF @adminRole IS NOT NULL INSERT INTO role_permissions(role_id,permission_id)
SELECT @adminRole,p.id FROM permissions p JOIN @perms x ON x.code=p.code WHERE NOT EXISTS (SELECT 1 FROM role_permissions rp WHERE rp.role_id=@adminRole AND rp.permission_id=p.id);

MERGE job_queues AS target USING (SELECT @org organization_id, 'ai-tool-operations' name) source
ON target.organization_id=source.organization_id AND target.name=source.name
WHEN MATCHED THEN UPDATE SET status='running', health_percent=98, updated_at=SYSUTCDATETIME()
WHEN NOT MATCHED THEN INSERT (organization_id,name,status,health_percent) VALUES (source.organization_id,source.name,'running',98);

DECLARE @wf TABLE(code NVARCHAR(120), name NVARCHAR(220));
INSERT INTO @wf VALUES ('AI_TOOL_REGISTRATION','AI Tool Registration'),('AI_TOOL_VALIDATION','AI Tool Validation'),('AI_TOOL_CONNECTION_TEST','AI Tool Connection Test'),('AI_TOOL_SCHEMA_VALIDATION','AI Tool Schema Validation'),('AI_TOOL_PERMISSION_VALIDATION','AI Tool Permission Validation'),('AI_TOOL_TEST_EXECUTION','AI Tool Test Execution'),('AI_TOOL_SIMULATION','AI Tool Simulation'),('AI_TOOL_CALL_EXECUTION','AI Tool Call Execution'),('AI_TOOL_AUTONOMOUS_RECOVERY','AI Tool Autonomous Recovery'),('AI_TOOL_FALLBACK_EXECUTION','AI Tool Fallback Execution'),('AI_TOOL_DEPRECATION_MIGRATION','AI Tool Deprecation Migration'),('AI_TOOL_VERSION_PUBLISH','AI Tool Version Publish'),('AI_TOOL_GOVERNANCE_APPROVAL','AI Tool Governance Approval');
MERGE workflow_definitions AS target USING (SELECT @org organization_id, code, name, 'ai_tool_operations' workflow_type FROM @wf) source
ON target.organization_id=source.organization_id AND target.code=source.code
WHEN MATCHED THEN UPDATE SET name=source.name, workflow_type=source.workflow_type, status='active', updated_at=SYSUTCDATETIME()
WHEN NOT MATCHED THEN INSERT (organization_id,code,name,workflow_type,status,is_system_workflow) VALUES (source.organization_id,source.code,source.name,source.workflow_type,'active',1);

DELETE FROM ai_tool_final_output_links WHERE organization_id=@org;
DELETE FROM ai_tool_recommendations WHERE organization_id=@org;
DELETE FROM ai_tool_calls WHERE organization_id=@org;
DELETE FROM ai_tool_security_policies WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
