DELETE FROM ai_tool_performance WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_circuit_breakers WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_fallbacks WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_quotas WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_rate_limits WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_workflow_usage WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_capability_mappings WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_agent_assignments WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_permissions WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_schemas WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tool_versions WHERE tool_id IN (SELECT id FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%');
DELETE FROM ai_tools WHERE organization_id=@org AND tool_code LIKE 'TOOL-%';
DELETE FROM ai_tool_lifecycle WHERE organization_id=@org;
DELETE FROM ai_tool_categories WHERE organization_id=@org;

DECLARE @cat TABLE(name NVARCHAR(180), tools INT, active INT, healthy INT, degraded INT, calls INT, success DECIMAL(8,2), latency DECIMAL(8,2), cost DECIMAL(18,4), agents INT, fallback DECIMAL(8,2), output DECIMAL(8,2), health DECIMAL(8,2));
INSERT INTO @cat VALUES
('Web Search Tools',5,5,5,0,8200,98.2,1.2,0.012,18,96,92,98),('Research Tools',4,4,4,0,6400,97.8,1.6,0.018,16,95,94,97),('Internal Search Tools',4,4,4,0,7200,98.9,0.7,0.004,14,99,91,99),('Knowledge Base Tools',4,4,4,0,6800,98.6,0.8,0.005,17,99,93,99),('Database Tools',4,4,3,1,4300,96.8,1.1,0.009,12,97,96,96),('File Retrieval Tools',4,4,4,0,3900,98.0,0.9,0.004,11,98,89,98),('Document Processing Tools',4,4,3,1,2400,95.9,2.2,0.026,9,94,88,94),('API Connector Tools',5,5,4,1,5200,96.2,1.9,0.020,18,93,91,95),('Webhook Tools',4,3,3,1,2600,95.8,1.4,0.006,8,92,85,94),('Image Generation Tools',4,4,4,0,1300,96.4,4.2,0.072,7,95,92,96),('Image Processing Tools',4,4,4,0,1800,97.2,2.6,0.028,8,96,90,97),('Voice Generation Tools',4,4,3,1,900,95.4,3.1,0.041,6,92,90,93),('Audio Processing Tools',4,4,3,1,1100,95.7,2.9,0.032,7,93,88,94),('Video Generation Tools',3,3,3,0,430,94.2,8.4,0.142,5,91,87,93),('Video Processing Tools',4,4,4,0,720,96.1,6.1,0.081,6,94,89,95),('Video Rendering Tools',3,3,2,1,620,94.9,9.2,0.116,5,91,91,92),('Publishing Tools',4,4,4,0,2200,98.0,1.7,0.015,12,98,98,98),('Social Media Tools',4,4,3,1,1800,96.1,2.1,0.018,9,94,93,95),('SEO Tools',4,4,4,0,2800,98.1,1.1,0.006,10,96,91,98),('Analytics Tools',4,4,4,0,4800,99.0,0.9,0.004,13,99,90,99),('Reporting Tools',4,4,4,0,1200,97.3,1.8,0.012,8,96,88,97),('Notification Tools',4,4,4,0,6200,99.2,0.6,0.002,14,99,84,99),('Email Tools',4,4,3,1,3200,97.0,1.3,0.003,10,95,83,96),('Messaging Tools',4,4,4,0,4400,98.4,0.8,0.002,12,98,84,98),('Storage Tools',4,4,4,0,5100,98.7,0.9,0.005,13,99,90,99),('Workflow Tools',4,4,4,0,3700,98.0,0.8,0.003,15,98,96,98),('Scheduling Tools',4,4,4,0,900,98.5,0.7,0.002,7,99,85,99),('Moderation Tools',4,4,4,0,4600,99.4,0.5,0.003,16,99,96,99),('Security Tools',4,4,4,0,2100,98.9,0.9,0.007,10,98,95,99),('Code Execution Tools',3,2,2,1,620,94.5,3.2,0.038,4,90,78,91),('Translation Tools',4,4,4,0,1800,97.8,1.4,0.012,7,96,84,97),('OCR Tools',3,3,3,0,960,96.8,2.1,0.019,5,95,82,96),('Monitoring Tools',4,4,4,0,520